class TextEditor {
    private StringBuilder text;
    private int cursorPosition;

    public TextEditor() {
        text = new StringBuilder();
        cursorPosition = 0;
    }

    public void addText(String textToAdd) {
        text.insert(cursorPosition, textToAdd);
        cursorPosition += textToAdd.length();
    }

    public int deleteText(int k) {
        int actualDeleted = Math.min(k, cursorPosition);
        text.delete(cursorPosition - actualDeleted, cursorPosition);
        cursorPosition -= actualDeleted;
        return actualDeleted;
    }

    public String cursorLeft(int k) {
        cursorPosition = Math.max(0, cursorPosition - k);
        int leftTextLength = cursorPosition;
        return text.substring(Math.max(0, leftTextLength - 10), leftTextLength);
    }

    public String cursorRight(int k) {
        cursorPosition = Math.min(text.length(), cursorPosition + k);
        int leftTextLength = cursorPosition;
        return text.substring(Math.max(0, leftTextLength - 10), leftTextLength);
    }
}
```
